// src/components/common/Header.jsx
import React, { useContext, useState, useEffect } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { AuthContext } from "../../context/AuthContext";
import { CartContext } from "../../context/CartContext";
import { categoryAPI } from "../../api"; // đảm bảo path này đúng

const Header = () => {
  const { user, logout } = useContext(AuthContext);
  const { cartItems } = useContext(CartContext);
  const navigate = useNavigate();
  const location = useLocation();

  const [q, setQ] = useState("");
  const [category, setCategory] = useState("all");
  const [categories, setCategories] = useState([]);
  const [showCategories, setShowCategories] = useState(false);

  const cartCount = cartItems.reduce((t, it) => t + (it.quantity || 1), 0);

  useEffect(() => {
    (async () => {
      try {
        const res = await categoryAPI.getCategories();
        if (res?.data && Array.isArray(res.data)) setCategories(res.data);
        else setCategories([]);
      } catch (err) {
        console.error("Header: fetch categories", err);
        setCategories([]);
      }
    })();
  }, []);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    setQ(params.get("q") || "");
    setCategory(params.get("category") || "all");
  }, [location.search]);

  const handleSearch = (e) => {
    e?.preventDefault();
    const params = new URLSearchParams();
    if (q.trim()) params.set("q", q.trim());
    if (category !== "all") params.set("category", category);
    navigate(`/product${params.toString() ? `?${params.toString()}` : ""}`);
  };

  return (
    <>
      {/* Top thin bar */}
      <div className="topbar">
        <div className="container topbar-inner">
          <div className="topbar-left">🌸 DDT Flower Shop - Nơi gửi gắm yêu thương 🌸</div>
          <div className="topbar-right">
            {user ? (
              <>
                <Link to="/profile">{user.name}</Link>
                {user.role === "admin" && <Link to="/admin/dashboard">Quản trị</Link>}
                <button onClick={logout} className="link-btn">Đăng xuất</button>
              </>
            ) : (
              <Link to="/login" className="link-btn">Đăng nhập</Link>
            )}
          </div>
        </div>
      </div>

      {/* Main header */}
      <header className="site-header">
        <div className="container header-inner">
          <Link to="/" className="brand">
            <img src="/DTP.png" alt="logo" className="brand-logo" />
            <span className="brand-title">DDT Flower</span>
          </Link>

          <form className="search-wrap" onSubmit={handleSearch}>
            <select value={category} onChange={(e) => setCategory(e.target.value)} className="select-cat">
              <option value="all">Tất cả</option>
              {categories.map((c) => (
                <option key={c._id} value={c.slug || c._id}>{c.name}</option>
              ))}
            </select>
            <input
              className="search-input"
              value={q}
              onChange={(e) => setQ(e.target.value)}
              placeholder="Tìm kiếm hoa..."
            />
            <button className="search-btn" type="submit">🔍</button>
          </form>

          <div className="header-actions">
            <Link to="/product" className="nav-link">Trang chủ</Link>
            <Link to="/product" className="nav-link">Sản phẩm</Link>
            <Link to="/cart" className="cart-btn">
              🛒 Giỏ hàng
              {cartCount > 0 && <span className="cart-count">{cartCount}</span>}
            </Link>
          </div>
        </div>
      </header>

      {/* Secondary green nav (category dropdown and breadcrumbs) */}
      <nav className="secondary-nav">
        <div className="container sec-inner">
          <div className="cat-dropdown">
            <button onClick={() => setShowCategories(!showCategories)} className="cat-btn">
              ☰ DANH MỤC SẢN PHẨM {categories.length ? `(${categories.length})` : ""}
            </button>
            {showCategories && (
              <div className="cat-panel">
                <ul className="cat-list">
                  {categories.map((c) => (
                    <li key={c._id}><Link to={`/category/${c.slug || c._id}`} onClick={()=>setShowCategories(false)}>{c.name}</Link></li>
                  ))}
                </ul>
              </div>
            )}
          </div>

          <div className="breadcrumb-links">
            <Link to="/">Trang chủ</Link>
            <span>/</span>
            <Link to="/product">Sản phẩm</Link>
          </div>
        </div>
      </nav>
    </>
  );
};

export default Header;
